class Solution(object):
    def isPossible(self, n, edges):
        """
        :type n: int
        :type edges: List[List[int]]
        :rtype: bool
        """
        # Build adjacency set
        adj = {i: set() for i in range(1, n + 1)}
        for u, v in edges:
            adj[u].add(v)
            adj[v].add(u)

        # Find nodes with odd degree
        odd_nodes = [i for i in range(1, n + 1) if len(adj[i]) % 2 == 1]

        # No nodes with odd degree
        if len(odd_nodes) == 0:
            return True

        # If more than 4 nodes with odd degree, impossible
        if len(odd_nodes) > 4:
            return False

        # Case: 2 nodes with odd degree
        if len(odd_nodes) == 2:
            u, v = odd_nodes
            # Can connect directly if no edge exists
            if v not in adj[u]:
                return True
            # Try connecting through intermediate node
            for x in range(1, n + 1):
                if x != u and x != v and u not in adj[x] and v not in adj[x]:
                    return True
            return False

        # Case: 4 nodes with odd degree
        if len(odd_nodes) == 4:
            a, b, c, d = odd_nodes
            # Try pairing a-b and c-d
            if b not in adj[a] and d not in adj[c]:
                return True
            if d not in adj[a] and b not in adj[c]:
                return True
            if c not in adj[a] and b not in adj[d]:
                return True
            # Try connecting through intermediate nodes
            for x in range(1, n + 1):
                if x not in odd_nodes:
                    if (a not in adj[x] and b not in adj[x] and 
                        c not in adj[x] and d not in adj[x]):
                        return True
            return False

        return False
